
console.info('Smart Task Flow app.js v20260625-full-calendar-restored-3status loaded');

function getStatusKorean(s){return {PENDING:'진행 대기',PROGRESS:'진행 중',COMPLETED:'완료됨',OVERDUE:'기한 초과'}[s]||'전체';}
function getPriorityBadge(p){return p==='HIGH'?'높음':p==='NORMAL'?'보통':'낮음';}
function getStatusIcon(s){return s==='COMPLETED'?'✅':s==='PROGRESS'?'⚙️':'⌛';}
function normalizeStatus(s){return ['PENDING','PROGRESS','COMPLETED'].includes(s)?s:'PENDING';}
function getTodayStr(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;}
function getFutureDateStr(days){const d=new Date();d.setDate(d.getDate()+days);return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;}
function escapeHTML(str){if(!str)return '';return String(str).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));}
function getAvatarStyle(name){if(!name)return AVATAR_COLORS[0];let sum=0;String(name).split('').forEach(ch=>sum+=ch.charCodeAt(0));return AVATAR_COLORS[sum%AVATAR_COLORS.length];}
function getTimelineStatus(dueStr,status){if(status==='COMPLETED')return{text:'완료됨',class:'bg-emerald-50 text-emerald-700 border-emerald-100'};const today=getTodayStr();const diff=Math.ceil((new Date(String(dueStr||today).replace(/-/g,'/'))-new Date(today.replace(/-/g,'/')))/86400000);if(diff<0)return{text:`기한 초과 (D+${Math.abs(diff)})`,class:'bg-rose-50 text-rose-700 border-rose-100 font-semibold'};if(diff===0)return{text:'오늘 마감',class:'bg-amber-50 text-amber-700 border-amber-200 font-semibold'};return{text:`D-${diff}`,class:'bg-slate-100 text-slate-700 border-slate-200'};}
function showToast(msg,ok=true){const t=document.getElementById('toast'),txt=document.getElementById('toast-text'),ic=document.getElementById('toast-icon');if(!t||!txt){console.info(msg);return;}txt.textContent=msg;if(ic)ic.textContent=ok?'✅':'⚠️';t.classList.remove('translate-y-10','opacity-0');t.classList.add('translate-y-0','opacity-100');setTimeout(()=>{t.classList.remove('translate-y-0','opacity-100');t.classList.add('translate-y-10','opacity-0');},3500);}
function getServerTimestamp(){return(typeof firebase!=='undefined'&&firebase.firestore&&firebase.firestore.FieldValue)?firebase.firestore.FieldValue.serverTimestamp():new Date().toISOString();}
function canWriteToFirestore(){if(!isFirebaseAvailable||!db)return false;if(auth&&!isAuthReady){showToast('Firebase 인증 준비 중입니다. 잠시 후 다시 시도해 주세요.',false);return false;}return true;}
function markSaving(){lastSaveState='saving';}function markSaved(){lastSaveState='saved';}function markSaveError(){lastSaveState='error';}

let pendingTrackerOrderSignature=null,isTrackerOrderSaving=false;
function sortTrackersByOrder(list){return[...(list||[])].sort((a,b)=>(a.order??999999)-(b.order??999999)||(a.name||'').localeCompare(b.name||''));}
function normalizeTrackerOrder(list){return(list||[]).map((t,i)=>({...t,order:i+1}));}
function getTrackerOrderSignature(list){return(list||[]).map(t=>t&&t.id).filter(Boolean).join('|');}

async function db_addTask(data){const id='task_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);const now=getServerTimestamp();const tracker=trackers.find(t=>t.id===currentTrackerId);const payload={...data,trackerId:data.trackerId||currentTrackerId,trackerName:tracker?tracker.name:'',deleted:false,createdAt:now,updatedAt:now};markSaving();const coll=getTasksCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set(payload,{merge:true});markSaved();}catch(e){markSaveError();showToast('Firebase 저장 실패',false);}}if(!tasks.some(t=>t.id===id))tasks.push({id,...payload});updateUI();}
async function db_updateTask(id,data){const tracker=trackers.find(t=>t.id===(data.trackerId||currentTrackerId));const payload={...data,trackerName:tracker?tracker.name:data.trackerName,updatedAt:getServerTimestamp()};markSaving();const coll=getTasksCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set(payload,{merge:true});markSaved();}catch(e){markSaveError();showToast('Firebase 수정 실패',false);}}const idx=tasks.findIndex(t=>t.id===id);if(idx!==-1)tasks[idx]={...tasks[idx],...payload};updateUI();}
async function db_deleteTask(id){const payload={deleted:true,deletedAt:getServerTimestamp(),updatedAt:getServerTimestamp()};const coll=getTasksCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set(payload,{merge:true});markSaved();}catch(e){markSaveError();showToast('Firebase 삭제 반영 실패',false);}}tasks=tasks.filter(t=>t.id!==id);selectedTaskIds.delete(id);updateUI();}
async function db_batchDelete(ids){const arr=Array.from(ids);const coll=getTasksCollection();if(canWriteToFirestore()&&coll){try{const batch=db.batch();arr.forEach(id=>batch.set(coll.doc(id),{deleted:true,deletedAt:getServerTimestamp(),updatedAt:getServerTimestamp()},{merge:true}));await batch.commit();markSaved();}catch(e){markSaveError();showToast('Firebase 일괄 삭제 실패',false);}}tasks=tasks.filter(t=>!arr.includes(t.id));ids.clear();updateUI();}
async function db_addTracker(data){const id='tracker_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);const next=trackers.length?Math.max(...trackers.map(t=>t.order??0))+1:1;const payload={...data,order:next,deleted:false,createdAt:getServerTimestamp(),updatedAt:getServerTimestamp()};const coll=getTrackersCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set(payload,{merge:true});markSaved();}catch(e){showToast('Firebase 트래커 저장 실패',false);}}trackers.push({id,...payload});currentTrackerId=id;localStorage.setItem('flow_current_tracker',id);updateTrackerUI();updateUI();}
async function db_updateTracker(id,data){const old=trackers.find(t=>t.id===id);const payload={...data,order:old?.order??data.order,updatedAt:getServerTimestamp()};const coll=getTrackersCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set(payload,{merge:true});markSaved();}catch(e){showToast('Firebase 트래커 수정 실패',false);}}const idx=trackers.findIndex(t=>t.id===id);if(idx!==-1)trackers[idx]={...trackers[idx],...payload};updateTrackerUI();updateUI();}
async function db_deleteTracker(id){const coll=getTrackersCollection(),tc=getTasksCollection();if(canWriteToFirestore()&&coll){try{await coll.doc(id).set({deleted:true,deletedAt:getServerTimestamp(),updatedAt:getServerTimestamp()},{merge:true});if(tc){const snap=await tc.where('trackerId','==',id).get();const batch=db.batch();snap.docs.forEach(d=>batch.set(d.ref,{deleted:true,deletedAt:getServerTimestamp(),updatedAt:getServerTimestamp()},{merge:true}));if(!snap.empty)await batch.commit();}markSaved();}catch(e){showToast('Firebase 트래커 삭제 실패',false);}}tasks=tasks.filter(t=>t.trackerId!==id);trackers=trackers.filter(t=>t.id!==id);if(!trackers.length)trackers.push({id:'tracker-default',name:'기본 업무 트래커',desc:'기본 설정된 초기 공간입니다.',order:1});currentTrackerId=trackers[0].id;localStorage.setItem('flow_current_tracker',currentTrackerId);updateTrackerUI();updateUI();}

function getFilteredTasks(){const search=(document.getElementById('filter-search')?.value||'').toLowerCase().trim(),status=document.getElementById('filter-status')?.value||'ALL',priority=document.getElementById('filter-priority')?.value||'ALL',assignee=document.getElementById('filter-assignee')?.value||'ALL',startDate=document.getElementById('filter-start-date')?.value||'',endDate=document.getElementById('filter-end-date')?.value||'',today=getTodayStr();return tasks.filter(t=>{if(t.deleted||t.trackerId!==currentTrackerId)return false;if(search&&!String(t.title||'').toLowerCase().includes(search)&&!String(t.assignee||'').toLowerCase().includes(search))return false;if(status==='OVERDUE'){if(t.status==='COMPLETED'||(t.dueDate||today)>=today)return false;}else if(status!=='ALL'&&t.status!==status)return false;if(priority!=='ALL'&&t.priority!==priority)return false;if(assignee!=='ALL'&&t.assignee!==assignee)return false;if(startDate&&(t.dueDate||today)<startDate)return false;if(endDate&&(t.startDate||today)>endDate)return false;return true;});}
function buildAssigneeDropdownFilter(){const sel=document.getElementById('filter-assignee');if(!sel)return;const cur=sel.value;const names=[...new Set(tasks.filter(t=>t.trackerId===currentTrackerId&&!t.deleted).map(t=>t.assignee).filter(Boolean))];sel.innerHTML='<option value="ALL">담당자: 전체</option>';names.forEach(n=>{const o=document.createElement('option');o.value=n;o.textContent=n;sel.appendChild(o);});if(names.includes(cur))sel.value=cur;}
function updateTrackerUI(){const box=document.getElementById('tracker-list-items');if(!box)return;box.innerHTML='';trackers=sortTrackersByOrder(trackers).map((t,i)=>({...t,order:t.order??i+1}));const cur=trackers.find(t=>t.id===currentTrackerId)||trackers[0];if(cur){currentTrackerId=cur.id;document.getElementById('current-tracker-name').textContent=cur.name;document.getElementById('current-tracker-desc').textContent=cur.desc||'실시간 업무 기한 관리 및 진척도 모니터링 시스템';}trackers.forEach(t=>{const row=document.createElement('div');row.className=`tracker-item group flex items-stretch gap-1 rounded-xl transition ${t.id===currentTrackerId?'bg-indigo-50 ring-1 ring-indigo-100':'hover:bg-slate-50'}`;row.dataset.id=t.id;row.innerHTML=`<button type="button" class="tracker-select flex-1 text-left px-3 py-2 rounded-xl"><div class="text-xs font-bold">${escapeHTML(t.name)}</div><div class="text-[10px] text-slate-400 truncate">${escapeHTML(t.desc||'상세 설명 없음')}</div></button><div class="flex flex-col py-1 pr-1"><button type="button" class="btn-tracker-up text-[10px] text-slate-400">▲</button><button type="button" class="btn-tracker-down text-[10px] text-slate-400">▼</button></div>`;row.querySelector('.tracker-select').addEventListener('click',()=>{currentTrackerId=t.id;localStorage.setItem('flow_current_tracker',t.id);document.getElementById('tracker-dropdown-menu')?.classList.add('hidden');updateTrackerUI();updateUI();showToast(`트래커 전환: ${t.name}`);});row.querySelector('.btn-tracker-up').addEventListener('click',e=>{e.stopPropagation();moveTrackerOrder(t.id,'up');});row.querySelector('.btn-tracker-down').addEventListener('click',e=>{e.stopPropagation();moveTrackerOrder(t.id,'down');});box.appendChild(row);});}
async function saveTrackerOrder(){trackers=normalizeTrackerOrder(trackers);pendingTrackerOrderSignature=getTrackerOrderSignature(trackers);isTrackerOrderSaving=true;updateTrackerUI();const coll=getTrackersCollection();if(canWriteToFirestore()&&coll){try{const batch=db.batch();trackers.forEach((t,i)=>batch.set(coll.doc(t.id),{order:i+1,updatedAt:getServerTimestamp()},{merge:true}));await batch.commit();markSaved();}catch(e){markSaveError();}}pendingTrackerOrderSignature=null;isTrackerOrderSaving=false;}
async function moveTrackerOrder(id,dir){trackers=sortTrackersByOrder(trackers);const i=trackers.findIndex(t=>t.id===id),j=dir==='up'?i-1:i+1;if(i<0||j<0||j>=trackers.length)return;const m=trackers.splice(i,1)[0];trackers.splice(j,0,m);trackers=normalizeTrackerOrder(trackers);updateTrackerUI();await saveTrackerOrder();}
async function moveTaskOrder(id,dir){const arr=tasks.filter(t=>t.trackerId===currentTrackerId).sort((a,b)=>(a.order??999)-(b.order??999));const i=arr.findIndex(t=>t.id===id),j=dir==='up'?i-1:i+1;if(i<0||j<0||j>=arr.length)return;const a=arr[i],b=arr[j],tmp=a.order;a.order=b.order;b.order=tmp;updateUI();await db_updateTask(a.id,{order:a.order});await db_updateTask(b.id,{order:b.order});}
function renderStats(){const s=tasks.filter(t=>t.trackerId===currentTrackerId&&!t.deleted),total=s.length,p=s.filter(t=>t.status==='PENDING').length,pr=s.filter(t=>t.status==='PROGRESS').length,c=s.filter(t=>t.status==='COMPLETED').length,today=getTodayStr(),o=s.filter(t=>t.status!=='COMPLETED'&&(t.dueDate||'')<today).length;[['stat-total',total],['stat-pending',p],['stat-progress',pr],['stat-completed',c],['stat-overdue',o],['stat-pending-pct',total?Math.round(p/total*100)+'%':'0%'],['stat-progress-pct',total?Math.round(pr/total*100)+'%':'0%'],['stat-completed-pct',total?Math.round(c/total*100)+'%':'0%']].forEach(([id,v])=>{const el=document.getElementById(id);if(el)el.textContent=v;});const l=document.getElementById('stat-overdue-lbl');if(l){l.textContent=o?'조속히 조치 필요':'매우 양호';l.className=`text-xs font-medium ${o?'text-rose-500 font-semibold':'text-emerald-500'}`;}}
function subSelect(parentId,subId,status,cls='rounded-lg border border-slate-200 bg-white px-2 py-1 text-[11px] font-semibold text-slate-600 outline-none focus:border-indigo-500'){status=normalizeStatus(status);return`<select class="sel-subtask-status ${cls}" data-task-id="${escapeHTML(parentId)}" data-subtask-id="${escapeHTML(subId)}"><option value="PENDING" ${status==='PENDING'?'selected':''}>진행 대기</option><option value="PROGRESS" ${status==='PROGRESS'?'selected':''}>진행 중</option><option value="COMPLETED" ${status==='COMPLETED'?'selected':''}>완료</option></select>`;}
function renderTable(filtered){const tbody=document.getElementById('task-table-body'),empty=document.getElementById('empty-state-table');if(!tbody)return;tbody.innerHTML='';if(!filtered.length){empty?.classList.replace('hidden','flex');updateSelectAllState(0,0);return;}empty?.classList.replace('flex','hidden');filtered.sort((a,b)=>(a.order??999)-(b.order??999)||(a.dueDate||'').localeCompare(b.dueDate||''));let selected=0;filtered.forEach(t=>{const subs=Array.isArray(t.subTasks)?t.subTasks:[],expanded=expandedTaskIds.has(t.id),chk=selectedTaskIds.has(t.id);if(chk)selected++;const timeline=getTimelineStatus(t.dueDate||getTodayStr(),t.status),done=subs.filter(s=>s.status==='COMPLETED').length;const tr=document.createElement('tr');tr.className='hover:bg-slate-50 transition-colors group';tr.innerHTML=`<td class="px-2 py-4 text-center text-slate-400"><button class="btn-order-up block mx-auto" data-id="${t.id}">▲</button><button class="btn-order-down block mx-auto" data-id="${t.id}">▼</button></td><td class="px-3 py-4 text-center"><input type="checkbox" class="cb-task rounded border-slate-300" data-id="${t.id}" ${chk?'checked':''}></td><td class="px-6 py-4"><div class="flex items-center gap-2"><button class="btn-toggle-subtasks text-slate-400 ${subs.length?'':'invisible'}" data-id="${t.id}">${subs.length?(expanded?'▼':'▶'):''}</button><span class="font-bold text-slate-900">${escapeHTML(t.title)}</span>${subs.length?`<span class="rounded-lg bg-slate-100 px-2 py-1 text-[10px] font-bold text-slate-600">하위 업무 ${done}/${subs.length}</span>`:''}</div><div class="pl-6 text-xs text-slate-400 mt-1">${escapeHTML(t.notes||'추가 지침 없음')}</div></td><td class="px-6 py-4"><div class="inline-flex items-center gap-2"><span class="inline-flex h-8 w-8 items-center justify-center rounded-full ${getAvatarStyle(t.assignee)} text-xs font-bold">${escapeHTML((t.assignee||'U').charAt(0))}</span><span class="font-semibold">${escapeHTML(t.assignee||'미지정')}</span></div></td><td class="px-6 py-4"><div class="text-xs font-semibold text-slate-600">${t.startDate?t.startDate.substring(5):'미정'} ~ ${(t.dueDate||'').substring(5)}</div><span class="mt-1 inline-flex rounded-lg border px-2 py-1 text-xs ${timeline.class}">${timeline.text}</span></td><td class="px-4 py-4 text-center"><span class="rounded-lg border border-slate-200 bg-white px-2 py-1 text-xs font-bold">${getPriorityBadge(t.priority)}</span></td><td class="px-6 py-4 text-center"><select class="sel-status rounded-xl border border-slate-200 bg-white px-3 py-2 text-xs font-semibold" data-id="${t.id}"><option value="PENDING" ${t.status==='PENDING'?'selected':''}>진행 대기 ⌛</option><option value="PROGRESS" ${t.status==='PROGRESS'?'selected':''}>진행 중 ⚙️</option><option value="COMPLETED" ${t.status==='COMPLETED'?'selected':''}>완료됨 ⭐️</option></select></td><td class="px-6 py-4 text-center"><button class="btn-edit text-slate-400 hover:text-indigo-600 px-2" data-id="${t.id}">✎</button><button class="btn-delete text-slate-400 hover:text-rose-600 px-2" data-id="${t.id}">🗑</button></td>`;tbody.appendChild(tr);if(subs.length&&expanded){subs.forEach(st=>{const status=normalizeStatus(st.status),subAssignee=st.assignee||t.assignee||'미지정';const sr=document.createElement('tr');sr.className='bg-slate-50/70 border-l-2 border-l-indigo-500/40 hover:bg-indigo-50/30 transition-colors text-xs';sr.innerHTML=`<td colspan="2"></td><td class="px-6 py-2 text-slate-600"><div class="flex items-center gap-2 pl-8"><span class="text-slate-300">└─</span><span class="font-semibold ${status==='COMPLETED'?'line-through text-slate-400':'text-slate-700'}">${escapeHTML(st.title)}</span><span class="rounded border border-indigo-100 bg-indigo-50 px-1 py-0.5 text-[10px] font-bold text-indigo-700">👤 ${escapeHTML(subAssignee)}</span></div></td><td class="px-6 py-2 text-center text-slate-400">-</td><td class="px-6 py-2 text-slate-500">📅 ${st.startDate?st.startDate.substring(5):'미정'} ~ ${st.dueDate?st.dueDate.substring(5):'미정'}</td><td class="px-4 py-2 text-center text-slate-400">-</td><td class="px-6 py-2 text-center">${subSelect(t.id,st.id,status)}</td><td class="px-6 py-2 text-center text-slate-300">-</td>`;tbody.appendChild(sr);});}});updateSelectAllState(filtered.length,selected);}
function rangeOverlaps(item,start,end,fallback){const s=new Date(String(item.startDate||item.dueDate||fallback).replace(/-/g,'/')),e=new Date(String(item.dueDate||item.startDate||fallback).replace(/-/g,'/'));return!isNaN(s)&&!isNaN(e)&&s<=end&&e>=start;}
function getMonthlySubTasks(t,ms,me,today){const all=Array.isArray(t.subTasks)?t.subTasks:[];return{allSubTasks:all,visibleSubTasks:all.filter(st=>rangeOverlaps(st,ms,me,today))};}
function buildMonthlySubTaskHTML(t,ms,me,today){const {allSubTasks,visibleSubTasks}=getMonthlySubTasks(t,ms,me,today);if(!allSubTasks.length||!visibleSubTasks.length)return'';let html='<div class="mt-2 space-y-1">';visibleSubTasks.forEach(st=>{const s=normalizeStatus(st.status);html+=`<div class="truncate text-[10px] ${s==='COMPLETED'?'text-slate-400 line-through':s==='PROGRESS'?'text-blue-600':'text-slate-600'}">${getStatusIcon(s)} ${escapeHTML(st.title)} <span class="text-slate-400">${st.dueDate?st.dueDate.substring(5):''}</span></div>`;});const h=allSubTasks.length-visibleSubTasks.length;if(h>0)html+=`<div class="text-[10px] text-slate-400">외 ${h}건 숨김</div>`;return html+'</div>';}
function bindGanttTooltip(el,title,details){const tip=document.getElementById('gantt-tooltip');if(!tip||!el)return;el.addEventListener('mouseenter',()=>{tip.innerHTML=`<div class="font-bold mb-1">${escapeHTML(title||'')}</div><div>${String(details||'')}</div>`;tip.classList.remove('hidden');});el.addEventListener('mousemove',e=>{tip.style.left=e.clientX+15+'px';tip.style.top=e.clientY+15+'px';});el.addEventListener('mouseleave',()=>tip.classList.add('hidden'));}
function renderCalendar(filteredTasks){const year=currentCalDate.getFullYear(),month=currentCalDate.getMonth(),grid=document.getElementById('calendar-grid'),weekdayHeader=document.getElementById('calendar-weekday-header'),titleEl=document.getElementById('calendar-month-year'),today=getTodayStr();if(!grid)return;if(titleEl)titleEl.textContent=currentCalMode==='MONTH'?`${year}년 전체 Gantt 타임라인`:`${year}년 ${month+1}월`;const groups=filteredTasks.map(t=>{const ss=t.startDate||t.dueDate||today,ee=t.dueDate||today,g={id:t.id,title:t.title,startDate:ss>ee?ee:ss,dueDate:ee,status:t.status||'PENDING',priority:t.priority||'NORMAL',assignee:t.assignee||'미지정',notes:t.notes||'',order:t.order??999,subTasks:(t.subTasks||[]).map(st=>{const a=st.startDate||st.dueDate||ee,b=st.dueDate||ee;return{id:st.id,title:st.title,startDate:a>b?b:a,dueDate:b,status:normalizeStatus(st.status),assignee:st.assignee||t.assignee||'미지정',parentId:t.id,parentTitle:t.title};})};g.rangeStart=g.startDate;g.rangeEnd=g.dueDate;g.subTasks.forEach(st=>{if(st.startDate<g.rangeStart)g.rangeStart=st.startDate;if(st.dueDate>g.rangeEnd)g.rangeEnd=st.dueDate;});return g;}).sort((a,b)=>a.order-b.order||a.rangeStart.localeCompare(b.rangeStart));const lines=[];groups.forEach(g=>{const need=isCalSubTaskVisible?1+g.subTasks.length:1;let s=0;while(true){let overlap=false;for(let l=0;l<need;l++){if(!lines[s+l])lines[s+l]=[];if(lines[s+l].some(o=>g.rangeStart<=o.end&&o.start<=g.rangeEnd)){overlap=true;break;}}if(!overlap){for(let l=0;l<need;l++)lines[s+l].push({start:g.rangeStart,end:g.rangeEnd});g.globalLineStart=s;break;}s++;}});const mainClass=g=>today>g.dueDate&&g.status!=='COMPLETED'?'bg-rose-100 text-rose-800 border border-rose-200':g.status==='COMPLETED'?'bg-emerald-100 text-emerald-800 border border-emerald-200':g.status==='PROGRESS'?'bg-blue-100 text-blue-800 border border-blue-200':'bg-slate-200 text-slate-700';const subClass=s=>s==='COMPLETED'?'bg-emerald-50/80 text-emerald-800 border border-dashed border-emerald-300':s==='PROGRESS'?'bg-blue-50/80 text-blue-800 border border-dashed border-blue-300':'bg-slate-50 text-slate-700 border border-dashed border-slate-300';if(currentCalMode==='DAY'){weekdayHeader?.classList.remove('hidden');grid.className='grid grid-cols-7 gap-px bg-slate-200 border border-slate-200 rounded-b-lg overflow-hidden relative z-10';grid.innerHTML='';const first=new Date(year,month,1).getDay(),days=new Date(year,month+1,0).getDate();for(let i=0;i<first;i++){const c=document.createElement('div');c.className='bg-slate-50 min-h-[130px] border-r border-b border-slate-100';grid.appendChild(c);}for(let d=1;d<=days;d++){const ds=`${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`,ci=first+d-1,dow=ci%7,weekStart=dow===0;const cell=document.createElement('div');cell.className=`bg-white min-h-[130px] flex flex-col transition-colors border-r border-b border-slate-100 ${ds===today?'bg-indigo-50/20':'hover:bg-slate-50'}`;cell.innerHTML=`<div class="p-1.5"><span class="inline-flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold ${ds===today?'bg-indigo-600 text-white shadow-sm':dow===0?'text-rose-500':dow===6?'text-blue-500':'text-slate-600'}">${d}</span></div>`;const box=document.createElement('div');box.className='flex flex-col flex-1 pb-1';const items=[];groups.forEach(g=>{if(ds>=g.startDate&&ds<=g.dueDate)items.push({id:g.id,title:g.title,isSub:false,status:g.status,lane:g.globalLineStart,start:g.startDate,end:g.dueDate,parentId:g.id,assignee:g.assignee,notes:g.notes,dueDate:g.dueDate});if(isCalSubTaskVisible)g.subTasks.forEach((st,i)=>{if(ds>=st.startDate&&ds<=st.dueDate)items.push({...st,isSub:true,lane:g.globalLineStart+1+i,start:st.startDate,end:st.dueDate,parentId:g.id,parentTitle:g.title});});});const max=Math.max(...items.map(x=>x.lane),-1);for(let l=0;l<=max;l++){const it=items.find(x=>x.lane===l);if(!it){const sp=document.createElement('div');sp.className='h-[22px] mb-1';box.appendChild(sp);continue;}const isStart=ds===it.start,isEnd=ds===it.end,show=isStart||weekStart;let shape='h-[22px] flex items-center mb-1 shadow-sm';if(isStart&&isEnd)shape+=' rounded mx-1 px-1.5';else if(isStart)shape+=' rounded-l ml-1 mr-0 pr-0 pl-1.5';else if(isEnd)shape+=' rounded-r mr-1 ml-0 pl-0 pr-1.5';else shape+=' mx-0 px-0 rounded-none';if(!isStart&&!weekStart)shape+=' -ml-[1px] relative z-10';const el=document.createElement('div');el.className=`text-[10px] font-semibold cursor-pointer transition-all hover:scale-[1.02] ${it.isSub?subClass(it.status):mainClass(it)} ${shape}`;el.onclick=()=>openTaskModal(it.parentId);bindGanttTooltip(el,it.title,it.isSub?`[하위업무] 상위: ${escapeHTML(it.parentTitle)}<br>담당자: ${escapeHTML(it.assignee)}<br>기간: ${it.start} ~ ${it.end}<br>상태: ${getStatusKorean(it.status)}`:`[본업무] 담당자: ${escapeHTML(it.assignee)}<br>기간: ${it.start} ~ ${it.end}<br>메모: ${escapeHTML(it.notes||'없음')}`);if(show){const txt=document.createElement('div');txt.className='truncate w-full whitespace-nowrap z-20';txt.innerHTML=it.isSub?`${getStatusIcon(it.status)} ↳ 👤 ${escapeHTML(it.assignee)} | ${escapeHTML(it.title)}`:`${it.status==='COMPLETED'?'⭐️':it.status==='PROGRESS'?'⚙️':'⌛'} ${escapeHTML(it.title)}`;el.appendChild(txt);}box.appendChild(el);}cell.appendChild(box);grid.appendChild(cell);}const total=first+days,remain=total%7===0?0:7-total%7;for(let i=0;i<remain;i++){const c=document.createElement('div');c.className='bg-slate-50 min-h-[130px] border-r border-b border-slate-100';grid.appendChild(c);}return;}if(currentCalMode==='MONTH'){weekdayHeader?.classList.add('hidden');grid.className='relative bg-white border border-slate-200 rounded-xl overflow-hidden';grid.innerHTML='';const head=document.createElement('div');head.className='grid grid-cols-12 gap-px bg-slate-50 relative z-20 border-b border-slate-200/80 shadow-sm';for(let m=1;m<=12;m++){const h=document.createElement('div');h.className='py-3 text-center text-xs font-bold text-slate-700';h.textContent=`${m}월`;head.appendChild(h);}grid.appendChild(head);const body=document.createElement('div');body.className='relative z-10 w-full';const tiles=document.createElement('div');tiles.className='grid grid-cols-12 gap-px bg-slate-100/50';const rowH=28,totalLines=lines.length>5?lines.length:5,height=totalLines*rowH+20;for(let i=0;i<12;i++){const tile=document.createElement('div');tile.className='bg-white border-b border-slate-100';tile.style.height=`${height}px`;tiles.appendChild(tile);}body.appendChild(tiles);const overlay=document.createElement('div');overlay.className='absolute inset-0 pointer-events-none';groups.forEach(g=>{const sd=new Date(g.rangeStart.replace(/-/g,'/')),ed=new Date(g.rangeEnd.replace(/-/g,'/'));if(sd.getFullYear()>year||ed.getFullYear()<year)return;const ts=new Date(g.startDate.replace(/-/g,'/')),te=new Date(g.dueDate.replace(/-/g,'/')),sm=ts.getFullYear()<year?0:ts.getMonth(),em=te.getFullYear()>year?11:te.getMonth();const bar=document.createElement('div');bar.className=`absolute h-5 rounded-lg shadow-sm text-[10.5px] font-bold flex items-center px-2 cursor-pointer transition-all hover:scale-[1.01] pointer-events-auto truncate z-10 ${mainClass(g)}`;bar.style.left=`calc(${sm/12*100}% + 4px)`;bar.style.width=`calc(${(em-sm+1)/12*100}% - 8px)`;bar.style.top=`${g.globalLineStart*rowH+10}px`;bar.onclick=()=>openTaskModal(g.id);bar.innerHTML=`${g.status==='COMPLETED'?'⭐️':g.status==='PROGRESS'?'⚙️':'⌛'} ${escapeHTML(g.title)}`;bindGanttTooltip(bar,g.title,`담당자: ${escapeHTML(g.assignee)}<br>기간: ${g.startDate} ~ ${g.dueDate}<br>설명: ${escapeHTML(g.notes||'없음')}`);overlay.appendChild(bar);if(isCalSubTaskVisible)g.subTasks.forEach((st,i)=>{const ssd=new Date(st.startDate.replace(/-/g,'/')),sed=new Date(st.dueDate.replace(/-/g,'/'));if(ssd.getFullYear()>year||sed.getFullYear()<year)return;const ssm=ssd.getFullYear()<year?0:ssd.getMonth(),sem=sed.getFullYear()>year?11:sed.getMonth();const sb=document.createElement('div');sb.className=`absolute h-5 rounded-lg shadow-sm text-[9.5px] font-bold flex items-center px-1.5 cursor-pointer transition-all hover:scale-[1.01] pointer-events-auto truncate ${subClass(st.status)}`;sb.style.left=`calc(${ssm/12*100}% + 4px)`;sb.style.width=`calc(${(sem-ssm+1)/12*100}% - 8px)`;sb.style.top=`${(g.globalLineStart+1+i)*rowH+10}px`;sb.onclick=()=>openTaskModal(g.id);sb.innerHTML=`${getStatusIcon(st.status)} ↳ 👤 ${escapeHTML(st.assignee)} | ${escapeHTML(st.title)}`;bindGanttTooltip(sb,st.title,`상위 업무: ${escapeHTML(g.title)}<br>담당자: ${escapeHTML(st.assignee)}<br>기간: ${st.startDate} ~ ${st.dueDate}<br>상태: ${getStatusKorean(st.status)}`);overlay.appendChild(sb);});});body.appendChild(overlay);grid.appendChild(body);return;}weekdayHeader?.classList.add('hidden');grid.className='flex flex-col gap-4 bg-slate-50 border border-slate-100 p-5 rounded-xl min-h-[250px]';grid.innerHTML='';const ms=new Date(year,month,1),me=new Date(year,month+1,0,23,59,59),cur=filteredTasks.filter(t=>rangeOverlaps(t,ms,me,today));if(!cur.length){grid.innerHTML=`<div class="text-sm text-slate-400">현재 조건 혹은 조회 기간 중 해당 월(${month+1}월)의 업무 정보가 존재하지 않습니다.</div>`;return;}const cats={OVERDUE:[],PROGRESS:[],PENDING:[],COMPLETED:[]};cur.forEach(t=>{if(t.status!=='COMPLETED'&&(t.dueDate||'')<today)cats.OVERDUE.push(t);else cats[t.status||'PENDING'].push(t);});const total=cur.length,complete=cats.COMPLETED.length,over=cats.OVERDUE.length,subTotal=cur.reduce((s,t)=>s+((t.subTasks||[]).length),0),subDone=cur.reduce((s,t)=>s+(t.subTasks||[]).filter(st=>st.status==='COMPLETED').length,0);const panel=document.createElement('div');panel.className='grid grid-cols-2 md:grid-cols-4 gap-3';panel.innerHTML=`<div class="bg-white rounded-xl p-3 border"><div class="text-xs text-slate-400">월간 업무</div><div class="text-xl font-bold">${total}</div><div class="text-[10px] text-slate-400">진행 ${cats.PROGRESS.length} · 대기 ${cats.PENDING.length}</div></div><div class="bg-white rounded-xl p-3 border"><div class="text-xs text-slate-400">완료율</div><div class="text-xl font-bold">${Math.round(complete/total*100)}%</div><div class="text-[10px] text-slate-400">완료 ${complete}/${total}</div></div><div class="bg-white rounded-xl p-3 border"><div class="text-xs text-slate-400">지연율</div><div class="text-xl font-bold text-rose-600">${Math.round(over/total*100)}%</div><div class="text-[10px] text-slate-400">지연 ${over}/${total}</div></div><div class="bg-white rounded-xl p-3 border"><div class="text-xs text-slate-400">하위 업무 완료</div><div class="text-xl font-bold">${subDone}/${subTotal}</div></div>`;grid.appendChild(panel);[{key:'OVERDUE',label:'🚨 일정 초과 및 지연 상태',style:'bg-rose-50/75 border-rose-100 text-rose-800'},{key:'PROGRESS',label:'⚙️ 현재 적극 진행 중',style:'bg-blue-50/75 border-blue-100 text-blue-800'},{key:'PENDING',label:'⌛ 대기 및 진행 준비 중',style:'bg-amber-50/75 border-amber-100 text-amber-800'},{key:'COMPLETED',label:'⭐️ 정상 완료 항목',style:'bg-emerald-50/75 border-emerald-100 text-emerald-800'}].forEach(cat=>{if(!cats[cat.key].length)return;const sec=document.createElement('div');sec.className=`rounded-xl border p-4 ${cat.style}`;sec.innerHTML=`<h4 class="font-bold mb-3">${cat.label} <span class="text-xs opacity-70">${cats[cat.key].length}건</span></h4>`;const cards=document.createElement('div');cards.className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2.5';cats[cat.key].forEach(t=>{const {allSubTasks,visibleSubTasks}=getMonthlySubTasks(t,ms,me,today),badge=allSubTasks.length?`<span class="rounded bg-slate-100 px-1.5 py-0.5 text-[10px] text-slate-600">하위 ${visibleSubTasks.length}/${allSubTasks.length}</span>`:'';const card=document.createElement('div');card.className='bg-white rounded-xl p-3 border border-slate-200/60 shadow-sm cursor-pointer hover:border-indigo-400';card.onclick=()=>openTaskModal(t.id);card.innerHTML=`<div class="font-bold text-sm text-slate-800">${escapeHTML(t.title)}</div><div class="mt-1 text-xs text-slate-500">${badge} 🗓️ ${t.startDate?t.startDate.substring(5):'미정'} ~ ${(t.dueDate||'').substring(5)} · ${escapeHTML(t.assignee||'미지정')}</div>${buildMonthlySubTaskHTML(t,ms,me,today)}`;cards.appendChild(card);});sec.appendChild(cards);grid.appendChild(sec);});}
function renderActiveViews(){const filtered=getFilteredTasks(),fs=document.getElementById('filter-status')?.value||'ALL';document.querySelectorAll('.filter-card').forEach(c=>c.classList.remove('ring-2','ring-indigo-600','bg-indigo-50/10'));document.getElementById(`card-${fs}`)?.classList.add('ring-2','ring-indigo-600','bg-indigo-50/10');renderTable(filtered);if(currentViewMode==='CALENDAR')renderCalendar(filtered);}
function updateUI(){renderStats();buildAssigneeDropdownFilter();renderActiveViews();updateUndoButton();}
function resetSubTaskButton(){const btn=document.getElementById('btn-add-subtask');if(btn){btn.textContent='추가';btn.className='rounded-lg bg-slate-800 px-4 py-1.5 text-xs font-bold text-white hover:bg-slate-700 transition shrink-0 ml-auto';}}
function addSubTaskToModalList(){const title=document.getElementById('input-subtask-title'),ass=document.getElementById('input-subtask-assignee'),st=document.getElementById('input-subtask-start'),du=document.getElementById('input-subtask-due'),val=(title?.value||'').trim();if(!val)return;const final=(ass?.value||'').trim()||(document.getElementById('input-task-assignee')?.value||'').trim()||'미지정',payload={title:val,assignee:final,startDate:st?.value||getTodayStr(),dueDate:du?.value||getTodayStr()};if(editingSubTaskIndex>-1&&currentSubTasks[editingSubTaskIndex]){currentSubTasks[editingSubTaskIndex]={...currentSubTasks[editingSubTaskIndex],...payload,status:normalizeStatus(currentSubTasks[editingSubTaskIndex].status)};editingSubTaskIndex=-1;resetSubTaskButton();}else currentSubTasks.push({id:'sub_'+Date.now()+'_'+Math.random().toString(36).slice(2,7),status:'PENDING',...payload});if(title)title.value='';if(ass)ass.value='';if(st)st.value=getTodayStr();if(du)du.value=getFutureDateStr(7);renderModalSubTasks();}
function renderModalSubTasks(){const box=document.getElementById('subtask-list-container');if(!box)return;box.innerHTML='';if(!currentSubTasks.length){box.innerHTML='<li class="rounded-xl border border-dashed border-slate-200 bg-slate-50 px-3 py-2 text-xs text-slate-400">등록된 하위 과제가 없습니다.</li>';return;}currentSubTasks.forEach((s,i)=>{const status=normalizeStatus(s.status),li=document.createElement('li');li.className='flex flex-col gap-2 rounded-xl border border-slate-200/60 bg-slate-50 p-2 text-xs hover:bg-slate-100/50 sm:flex-row sm:items-center sm:justify-between';li.innerHTML=`<div class="flex min-w-0 flex-1 items-center gap-2"><span class="shrink-0 font-bold ${status==='COMPLETED'?'text-emerald-600':status==='PROGRESS'?'text-blue-600':'text-amber-500'}">${getStatusIcon(status)} ${getStatusKorean(status).replace('됨','')}</span><span class="min-w-0 truncate font-medium text-slate-700 ${status==='COMPLETED'?'line-through opacity-50':''}">${escapeHTML(s.title)} <span class="text-[10px] text-slate-400 font-semibold">📅 ${s.startDate?s.startDate.substring(5):'미정'} ~ ${s.dueDate?s.dueDate.substring(5):'미정'}</span> <span class="bg-indigo-50 text-indigo-700 border border-indigo-100 px-1 py-0.2 rounded text-[9px] font-bold">👤 ${escapeHTML(s.assignee||'미지정')}</span></span></div><div class="flex shrink-0 items-center justify-end gap-1.5"><select class="rounded-lg border border-slate-200 bg-white px-2 py-1 text-[11px] font-semibold text-slate-600 outline-none" onchange="updateSubTaskStatusInModal(${i}, this.value)"><option value="PENDING" ${status==='PENDING'?'selected':''}>진행 대기</option><option value="PROGRESS" ${status==='PROGRESS'?'selected':''}>진행 중</option><option value="COMPLETED" ${status==='COMPLETED'?'selected':''}>완료</option></select><button type="button" class="px-1 font-bold text-indigo-600" onclick="editSubTaskInModal(${i})">수정</button><span class="text-slate-300">|</span><button type="button" class="px-1 font-semibold text-rose-500" onclick="removeSubTaskFromModal(${i})">삭제</button></div>`;box.appendChild(li);});}
window.updateSubTaskStatusInModal=(i,s)=>{if(!currentSubTasks[i])return;currentSubTasks[i].status=normalizeStatus(s);renderModalSubTasks();};
window.editSubTaskInModal=i=>{const s=currentSubTasks[i];if(!s)return;editingSubTaskIndex=i;document.getElementById('input-subtask-title').value=s.title||'';document.getElementById('input-subtask-assignee').value=s.assignee||'';document.getElementById('input-subtask-start').value=s.startDate||'';document.getElementById('input-subtask-due').value=s.dueDate||'';const btn=document.getElementById('btn-add-subtask');if(btn){btn.textContent='수정 완료';btn.className='rounded-lg bg-indigo-600 px-4 py-1.5 text-xs font-bold text-white hover:bg-indigo-700 transition shrink-0 ml-auto';}};
window.removeSubTaskFromModal=i=>{currentSubTasks.splice(i,1);if(editingSubTaskIndex===i){editingSubTaskIndex=-1;resetSubTaskButton();}renderModalSubTasks();};
function openTaskModal(id=null){document.getElementById('form-task')?.reset();['input-subtask-title','input-subtask-assignee'].forEach(x=>{const el=document.getElementById(x);if(el)el.value='';});document.getElementById('input-subtask-start').value=getTodayStr();document.getElementById('input-subtask-due').value=getFutureDateStr(7);editingSubTaskIndex=-1;resetSubTaskButton();const title=document.getElementById('modal-title');if(id){const t=tasks.find(x=>x.id===id);if(!t)return;if(title)title.textContent='업무 상세 변경';document.getElementById('input-task-id').value=t.id;document.getElementById('input-task-title').value=t.title||'';document.getElementById('input-task-assignee').value=t.assignee||'';document.getElementById('input-task-start').value=t.startDate||'';document.getElementById('input-task-due').value=t.dueDate||'';document.getElementById('input-task-priority').value=t.priority||'NORMAL';document.getElementById('input-task-status').value=t.status||'PENDING';document.getElementById('input-task-notes').value=t.notes||'';document.getElementById('input-subtask-assignee').placeholder=`담당자 (기본: ${t.assignee||'본 업무 담당자'})`;currentSubTasks=Array.isArray(t.subTasks)?JSON.parse(JSON.stringify(t.subTasks)).map(s=>({...s,status:normalizeStatus(s.status)})):[];}else{if(title)title.textContent='새로운 업무 배정';document.getElementById('input-task-id').value='';document.getElementById('input-task-start').value=getTodayStr();document.getElementById('input-task-due').value=getFutureDateStr(7);document.getElementById('input-subtask-assignee').placeholder='담당자 (선택)';currentSubTasks=[];}renderModalSubTasks();document.getElementById('modal-task')?.classList.remove('hidden');}
function closeModal(){document.getElementById('modal-task')?.classList.add('hidden');}function closeConfirmModal(){document.getElementById('modal-confirm')?.classList.add('hidden');confirmActionCb=null;}function openTrackerModal(id=null){document.getElementById('form-tracker')?.reset();const del=document.getElementById('btn-delete-tracker');if(id){const t=trackers.find(x=>x.id===id);if(!t)return;document.getElementById('modal-tracker-title').textContent='트래커 정보 수정';document.getElementById('input-tracker-id').value=t.id;document.getElementById('input-tracker-name').value=t.name;document.getElementById('input-tracker-desc').value=t.desc||'';del?.classList.remove('hidden');}else{document.getElementById('modal-tracker-title').textContent='새 트래커 스페이스 추가';document.getElementById('input-tracker-id').value='';del?.classList.add('hidden');}document.getElementById('tracker-dropdown-menu')?.classList.add('hidden');document.getElementById('modal-tracker')?.classList.remove('hidden');}function closeTrackerModal(){document.getElementById('modal-tracker')?.classList.add('hidden');}
async function handleTrackerSubmit(e){e.preventDefault();const id=document.getElementById('input-tracker-id').value,data={name:document.getElementById('input-tracker-name').value.trim(),desc:document.getElementById('input-tracker-desc').value.trim()};if(id){await db_updateTracker(id,data);showToast('트래커가 수정되었습니다.');}else{await db_addTracker(data);showToast('새 트래커 공간이 생성되었습니다.');}closeTrackerModal();}
async function handleTaskSubmit(e){e.preventDefault();const id=document.getElementById('input-task-id').value,start=document.getElementById('input-task-start').value,due=document.getElementById('input-task-due').value;if(start&&due&&start>due)return showToast('시작일은 마감일보다 늦을 수 없습니다.',false);let order=1;if(!id){const scope=tasks.filter(t=>t.trackerId===currentTrackerId);if(scope.length)order=Math.max(...scope.map(x=>x.order??0))+1;}const data={trackerId:currentTrackerId,title:document.getElementById('input-task-title').value.trim(),assignee:document.getElementById('input-task-assignee').value.trim(),startDate:start,dueDate:due,priority:document.getElementById('input-task-priority').value,status:document.getElementById('input-task-status').value,notes:document.getElementById('input-task-notes').value.trim(),subTasks:currentSubTasks.map(s=>({...s,status:normalizeStatus(s.status)}))};if(!id)data.order=order;if(id){await db_updateTask(id,data);showToast('수정되었습니다.');}else{await db_addTask(data);showToast('추가되었습니다.');}closeModal();}
async function updateTaskStatus(id,s){await db_updateTask(id,{status:s});showToast(`상태 변경: ${getStatusKorean(s)}`);}async function updateSubTaskStatus(parentId,subId,s){const p=tasks.find(t=>t.id===parentId);if(!p||!Array.isArray(p.subTasks))return;await db_updateTask(parentId,{subTasks:p.subTasks.map(st=>st.id===subId?{...st,status:normalizeStatus(s)}:st)});showToast(`하위 업무 상태 변경: ${getStatusKorean(s)}`);}
function confirmDelete(id){const t=tasks.find(x=>x.id===id);if(!t)return;document.getElementById('confirm-title').textContent='업무 삭제 알림';document.getElementById('confirm-message').innerHTML=`'${escapeHTML(t.title)}' 업무를 삭제하시겠습니까?`;confirmActionCb=async()=>{await db_deleteTask(id);deletionHistory.push({timestamp:Date.now(),items:[t]});closeConfirmModal();showToast('삭제되었습니다.');};document.getElementById('modal-confirm')?.classList.remove('hidden');}
function confirmBatchDelete(){if(!selectedTaskIds.size)return;document.getElementById('confirm-title').textContent='선택한 업무 일괄 삭제';document.getElementById('confirm-message').innerHTML=`선택된 ${selectedTaskIds.size}개의 업무를 삭제하시겠습니까?`;confirmActionCb=async()=>{const del=[];selectedTaskIds.forEach(id=>{const t=tasks.find(x=>x.id===id);if(t)del.push(t);});await db_batchDelete(selectedTaskIds);deletionHistory.push({timestamp:Date.now(),items:del});closeConfirmModal();showToast(`${del.length}개 삭제됨.`);};document.getElementById('modal-confirm')?.classList.remove('hidden');}
async function undoDelete(){if(!deletionHistory.length)return;const last=deletionHistory.pop(),coll=getTasksCollection();if(canWriteToFirestore()&&coll){try{const batch=db.batch();last.items.forEach(t=>{const{id,...d}=t;batch.set(coll.doc(id),{...d,deleted:false,deletedAt:null,updatedAt:getServerTimestamp()},{merge:true});});await batch.commit();}catch(e){showToast('Firebase 복원 실패',false);}}last.items.forEach(t=>{if(!tasks.some(x=>x.id===t.id))tasks.push({...t,deleted:false,deletedAt:null});});showToast(`${last.items.length}개 복원됨.`);updateUI();}
function handleTableClick(e){const edit=e.target.closest('.btn-edit'),del=e.target.closest('.btn-delete'),tog=e.target.closest('.btn-toggle-subtasks'),up=e.target.closest('.btn-order-up'),down=e.target.closest('.btn-order-down');if(edit)openTaskModal(edit.dataset.id);if(del)confirmDelete(del.dataset.id);if(tog){const id=tog.dataset.id;expandedTaskIds.has(id)?expandedTaskIds.delete(id):expandedTaskIds.add(id);renderActiveViews();}if(up)moveTaskOrder(up.dataset.id,'up');if(down)moveTaskOrder(down.dataset.id,'down');}
function handleTableChange(e){const sel=e.target.closest('.sel-status'),sub=e.target.closest('.sel-subtask-status'),cb=e.target.closest('.cb-task');if(sel)updateTaskStatus(sel.dataset.id,sel.value);if(sub)updateSubTaskStatus(sub.dataset.taskId,sub.dataset.subtaskId,sub.value);if(cb){cb.checked?selectedTaskIds.add(cb.dataset.id):selectedTaskIds.delete(cb.dataset.id);renderActiveViews();updateBatchButton();}}
function toggleSelectAll(e){document.querySelectorAll('.cb-task').forEach(cb=>e.target.checked?selectedTaskIds.add(cb.dataset.id):selectedTaskIds.delete(cb.dataset.id));renderActiveViews();updateBatchButton();}function updateSelectAllState(total,sel){const cb=document.getElementById('checkbox-select-all');if(!cb)return;cb.disabled=total===0;cb.checked=total>0&&total===sel;cb.indeterminate=sel>0&&sel<total;updateBatchButton();}function updateBatchButton(){const btn=document.getElementById('btn-batch-delete');if(btn)selectedTaskIds.size?btn.classList.remove('hidden'):btn.classList.add('hidden');}function updateUndoButton(){const btn=document.getElementById('btn-undo');if(btn)deletionHistory.length?btn.classList.remove('hidden'):btn.classList.add('hidden');}function resetFilters(){['filter-search','filter-start-date','filter-end-date'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});['filter-status','filter-priority','filter-assignee'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='ALL';});renderActiveViews();}
function handleDeleteTrackerClick(){const id=document.getElementById('input-tracker-id').value,t=trackers.find(x=>x.id===id);if(!t)return;closeTrackerModal();document.getElementById('confirm-title').textContent='트래커 완전 삭제';document.getElementById('confirm-message').innerHTML=`정말 '${escapeHTML(t.name)}' 트래커를 삭제하시겠습니까?<br>* 이 트래커 소속의 모든 업무 데이터가 함께 삭제됩니다.`;confirmActionCb=async()=>{await db_deleteTracker(id);closeConfirmModal();showToast('트래커 및 소속 데이터가 제거되었습니다.');};document.getElementById('modal-confirm')?.classList.remove('hidden');}
function exportToJSON(){const data=tasks.filter(t=>t.trackerId===currentTrackerId),a=document.createElement('a');a.href='data:application/json;charset=utf-8,'+encodeURIComponent(JSON.stringify(data,null,4));a.download=`backup_${getTodayStr()}.json`;a.click();}function exportToCSV(){let csv='\uFEFF업무명,담당자,시작일,마감일,우선순위,상태,세부메모\n';tasks.filter(t=>t.trackerId===currentTrackerId).forEach(t=>csv+=`"${(t.title||'').replace(/"/g,'""')}","${(t.assignee||'').replace(/"/g,'""')}","${t.startDate||''}","${t.dueDate||''}","${getPriorityBadge(t.priority)}","${getStatusKorean(t.status)}","${(t.notes||'').replace(/"/g,'""')}"\n`);const url=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8;'})),a=document.createElement('a');a.href=url;a.download=`export_${getTodayStr()}.csv`;a.click();URL.revokeObjectURL(url);}async function importFromJSON(e){const file=e.target.files?.[0];if(!file)return;const r=new FileReader();r.onload=async ev=>{try{const arr=JSON.parse(ev.target.result);if(!Array.isArray(arr))throw new Error('배열 아님');for(const t of arr)await db_addTask({...t,trackerId:currentTrackerId});showToast('성공적으로 불러왔습니다.');}catch(err){showToast('읽기 오류 발생',false);}};r.readAsText(file);e.target.value='';}
function setCalMode(mode){currentCalMode=mode;['day','month','summary'].forEach(m=>{const b=document.getElementById(`btn-cal-mode-${m}`);if(b)b.className=m.toUpperCase()===mode?'rounded-lg bg-white px-3.5 py-1.5 text-slate-800 shadow-sm transition':'rounded-lg px-3.5 py-1.5 text-slate-500 hover:text-slate-800 transition';});const w=document.getElementById('toggle-subtask-cal-wrapper');if(w){if(mode==='DAY'||mode==='MONTH'){w.classList.remove('hidden');w.classList.add('inline-flex');}else{w.classList.add('hidden');w.classList.remove('inline-flex');}}renderActiveViews();}
async function ensureDefaultTrackersInFirestore(){if(!isFirebaseAvailable||!db)return;const coll=getTrackersCollection();if(!coll)return;try{for(let i=0;i<trackers.length;i++){const t=trackers[i],snap=await coll.doc(t.id).get();if(!snap.exists)await coll.doc(t.id).set({name:t.name,desc:t.desc||'',order:t.order||i+1,deleted:false,createdAt:getServerTimestamp(),updatedAt:getServerTimestamp()},{merge:true});}}catch(e){console.warn('기본 트래커 보정 실패',e);}}
function setupRealtimeListeners(){if(!isFirebaseAvailable||!db)return false;const tc=getTrackersCollection(),dc=getTasksCollection();if(!tc||!dc)return false;if(typeof unsubscribeTrackers==='function')unsubscribeTrackers();if(typeof unsubscribeTasks==='function')unsubscribeTasks();unsubscribeTrackers=tc.onSnapshot(snap=>{const inc=sortTrackersByOrder(snap.docs.map(d=>({id:d.id,...d.data()})).filter(t=>t.deleted!==true));trackers=inc.length?inc:trackers;const saved=localStorage.getItem('flow_current_tracker');if(saved&&trackers.some(t=>t.id===saved))currentTrackerId=saved;else if(!trackers.some(t=>t.id===currentTrackerId)&&trackers[0])currentTrackerId=trackers[0].id;updateTrackerUI();updateUI();},()=>showToast('트래커 실시간 동기화 오류',false));unsubscribeTasks=dc.onSnapshot(snap=>{tasks=snap.docs.map(d=>({id:d.id,...d.data()})).filter(t=>t.deleted!==true);updateTrackerUI();updateUI();},()=>showToast('업무 실시간 동기화 오류',false));return true;}
async function fetchInitialData(){await ensureDefaultTrackersInFirestore();if(!setupRealtimeListeners())updateUI();}
document.addEventListener('DOMContentLoaded',()=>{if(isFirebaseAvailable&&auth){const init=async()=>{if(typeof __initial_auth_token!=='undefined'&&__initial_auth_token)await auth.signInWithCustomToken(__initial_auth_token);else await auth.signInAnonymously();};init().then(()=>auth.onAuthStateChanged(u=>{isAuthReady=!!u;if(u)fetchInitialData();})).catch(e=>{console.error('Auth initialization failed',e);updateUI();});}else updateUI();const saved=localStorage.getItem('flow_current_tracker');if(saved&&trackers.some(t=>t.id===saved))currentTrackerId=saved;updateTrackerUI();document.getElementById('btn-add-task')?.addEventListener('click',()=>openTaskModal());document.getElementById('btn-export-csv')?.addEventListener('click',exportToCSV);document.getElementById('btn-export-json')?.addEventListener('click',exportToJSON);document.getElementById('btn-undo')?.addEventListener('click',undoDelete);document.getElementById('btn-batch-delete')?.addEventListener('click',confirmBatchDelete);document.getElementById('btn-import-trigger')?.addEventListener('click',()=>document.getElementById('input-import-json')?.click());document.getElementById('input-import-json')?.addEventListener('change',importFromJSON);document.getElementById('btn-tracker-dropdown')?.addEventListener('click',e=>{e.stopPropagation();document.getElementById('tracker-dropdown-menu')?.classList.toggle('hidden');});document.addEventListener('click',e=>{if(!e.target.closest('#tracker-dropdown-container'))document.getElementById('tracker-dropdown-menu')?.classList.add('hidden');});document.getElementById('btn-create-tracker-open')?.addEventListener('click',()=>openTrackerModal());document.getElementById('btn-edit-tracker-open')?.addEventListener('click',()=>openTrackerModal(currentTrackerId));document.querySelectorAll('.filter-card').forEach(card=>card.addEventListener('click',()=>{const s=card.getAttribute('data-status'),el=document.getElementById('filter-status');if(el)el.value=s;renderActiveViews();}));['filter-search','filter-start-date','filter-end-date'].forEach(id=>document.getElementById(id)?.addEventListener('input',renderActiveViews));['filter-status','filter-priority','filter-assignee'].forEach(id=>document.getElementById(id)?.addEventListener('change',renderActiveViews));document.getElementById('btn-reset-filters')?.addEventListener('click',resetFilters);document.getElementById('checkbox-select-all')?.addEventListener('change',toggleSelectAll);document.getElementById('task-table-body')?.addEventListener('click',handleTableClick);document.getElementById('task-table-body')?.addEventListener('change',handleTableChange);document.getElementById('btn-view-table')?.addEventListener('click',()=>{currentViewMode='TABLE';document.getElementById('view-table')?.classList.remove('hidden');document.getElementById('view-calendar')?.classList.add('hidden');renderActiveViews();});document.getElementById('btn-view-calendar')?.addEventListener('click',()=>{currentViewMode='CALENDAR';document.getElementById('view-table')?.classList.add('hidden');document.getElementById('view-calendar')?.classList.remove('hidden');renderActiveViews();});document.getElementById('btn-cal-mode-day')?.addEventListener('click',()=>setCalMode('DAY'));document.getElementById('btn-cal-mode-month')?.addEventListener('click',()=>setCalMode('MONTH'));document.getElementById('btn-cal-mode-summary')?.addEventListener('click',()=>setCalMode('SUMMARY'));document.getElementById('cb-show-subtasks-cal')?.addEventListener('change',e=>{isCalSubTaskVisible=e.target.checked;renderActiveViews();});document.getElementById('btn-prev-month')?.addEventListener('click',()=>{currentCalDate.setMonth(currentCalDate.getMonth()-1);renderActiveViews();});document.getElementById('btn-today-month')?.addEventListener('click',()=>{currentCalDate=new Date();renderActiveViews();});document.getElementById('btn-next-month')?.addEventListener('click',()=>{currentCalDate.setMonth(currentCalDate.getMonth()+1);renderActiveViews();});document.getElementById('btn-close-task-modal')?.addEventListener('click',closeModal);document.getElementById('btn-cancel-task')?.addEventListener('click',closeModal);document.getElementById('form-task')?.addEventListener('submit',handleTaskSubmit);document.getElementById('btn-add-subtask')?.addEventListener('click',addSubTaskToModalList);document.getElementById('btn-close-tracker-modal')?.addEventListener('click',closeTrackerModal);document.getElementById('btn-cancel-tracker')?.addEventListener('click',closeTrackerModal);document.getElementById('form-tracker')?.addEventListener('submit',handleTrackerSubmit);document.getElementById('btn-delete-tracker')?.addEventListener('click',handleDeleteTrackerClick);document.getElementById('btn-cancel-confirm')?.addEventListener('click',closeConfirmModal);document.getElementById('btn-action-confirm')?.addEventListener('click',()=>{if(confirmActionCb)confirmActionCb();});window.addEventListener('beforeunload',()=>{if(typeof unsubscribeTasks==='function')unsubscribeTasks();if(typeof unsubscribeTrackers==='function')unsubscribeTrackers();});});
